// Get data from both inputs
const leadsData = $input.all();
const appointmentsData = $('Read Appointments Sheet').all();

// Get date ranges
const now = DateTime.now().setZone('Europe/Bucharest');
const weekAgo = now.minus({ weeks: 1 });
const twoWeeksAgo = now.minus({ weeks: 2 });

// Calculate lead metrics
let thisWeekLeads = 0;
let lastWeekLeads = 0;
let leadsBySource = {};
let statusCounts = {};

for (const item of leadsData) {
  const lead = item.json;
  const createdAt = lead.created_at || lead.createdAt;

  if (createdAt) {
    const leadDate = DateTime.fromISO(createdAt);
    if (leadDate >= weekAgo) {
      thisWeekLeads++;
    } else if (leadDate >= twoWeeksAgo && leadDate < weekAgo) {
      lastWeekLeads++;
    }
  }

  // Count by source
  const source = lead.source || 'unknown';
  leadsBySource[source] = (leadsBySource[source] || 0) + 1;

  // Count by status
  const status = lead.status || 'unknown';
  statusCounts[status] = (statusCounts[status] || 0) + 1;
}

// Calculate appointment metrics
let thisWeekAppointments = 0;
let noShowCount = 0;
let completedCount = 0;
let cancelledCount = 0;

for (const item of appointmentsData) {
  const apt = item.json;
  const aptDate = apt.appointment_datetime || apt.appointment_date;

  if (aptDate) {
    const date = DateTime.fromISO(aptDate);
    if (date >= weekAgo) {
      thisWeekAppointments++;
    }
  }

  const status = apt.status || '';
  if (status === 'no_show') noShowCount++;
  if (status === 'completed') completedCount++;
  if (status === 'cancelled') cancelledCount++;
}

// Format report
const leadGrowth = lastWeekLeads > 0 
  ? ((thisWeekLeads - lastWeekLeads) / lastWeekLeads * 100).toFixed(1) 
  : 'N/A';

const noShowRate = thisWeekAppointments > 0 
  ? ((noShowCount / thisWeekAppointments) * 100).toFixed(1)
  : '0';

return [{
  json: {
    report_date: now.toFormat('dd MMMM yyyy'),
    report_week: now.weekNumber,
    total_leads: leadsData.length,
    this_week_leads: thisWeekLeads,
    last_week_leads: lastWeekLeads,
    lead_growth_percent: leadGrowth,
    leads_by_source: JSON.stringify(leadsBySource),
    leads_by_status: JSON.stringify(statusCounts),
    new_count: statusCounts.new || 0,
    contacted_count: statusCounts.contacted || 0,
    booked_count: (statusCounts.booked_pending || 0) + (statusCounts.booked_confirmed || 0),
    completed_count: statusCounts.completed || 0,
    lost_count: statusCounts.lost || 0,
    this_week_appointments: thisWeekAppointments,
    no_show_count: noShowCount,
    no_show_rate: noShowRate,
    cancelled_count: cancelledCount
  }
}];

const m = $input.first().json;

const leadsBySource = JSON.parse(m.leads_by_source || '{}');
const leadsByStatus = JSON.parse(m.leads_by_status || '{}');

const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; background: #f5f5f5; }
    .container { background: white; border-radius: 12px; padding: 30px; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
    h1 { color: #2563eb; border-bottom: 2px solid #2563eb; padding-bottom: 10px; margin-top: 0; }
    h2 { color: #374151; margin-top: 25px; font-size: 18px; }
    .metric-card { background: #f3f4f6; padding: 20px; border-radius: 8px; margin: 10px 0; text-align: center; }
    .metric-value { font-size: 32px; font-weight: bold; color: #2563eb; }
    .metric-label { color: #6b7280; font-size: 14px; margin-top: 5px; }
    .growth-positive { color: #10b981; font-weight: bold; }
    .growth-negative { color: #ef4444; font-weight: bold; }
    .metrics-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; }
    table { width: 100%; border-collapse: collapse; margin: 15px 0; }
    th, td { padding: 12px; text-align: left; border-bottom: 1px solid #e5e7eb; }
    th { background: #f9fafb; font-weight: 600; color: #374151; }
    .footer { margin-top: 30px; padding-top: 20px; border-top: 1px solid #e5e7eb; color: #6b7280; font-size: 12px; text-align: center; }
  </style>
</head>
<body>
  <div class="container">
    <h1>📊 Raport Săptămânal</h1>
    <p style="color: #6b7280;">Săptămâna ${m.report_week} | ${m.report_date}</p>

    <h2>📈 Lead-uri</h2>
    <div class="metrics-grid">
      <div class="metric-card">
        <div class="metric-value">${m.this_week_leads}</div>
        <div class="metric-label">Lead-uri această săptămână</div>
        <div class="${parseFloat(m.lead_growth_percent) >= 0 ? 'growth-positive' : 'growth-negative'}">
          ${m.lead_growth_percent !== 'N/A' ? (parseFloat(m.lead_growth_percent) >= 0 ? '↑' : '↓') + ' ' + Math.abs(parseFloat(m.lead_growth_percent)) + '%' : 'Prima săptămână'}
        </div>
      </div>
      <div class="metric-card">
        <div class="metric-value">${m.total_leads}</div>
        <div class="metric-label">Total lead-uri în bază</div>
      </div>
    </div>

    <h2>📅 Programări</h2>
    <div class="metrics-grid">
      <div class="metric-card">
        <div class="metric-value">${m.this_week_appointments}</div>
        <div class="metric-label">Programări această săptămână</div>
      </div>
      <div class="metric-card">
        <div class="metric-value" style="color: ${parseFloat(m.no_show_rate) > 15 ? '#ef4444' : '#10b981'};">${m.no_show_rate}%</div>
        <div class="metric-label">Rată No-Show</div>
      </div>
    </div>

    <h2>📊 Funnel de Conversie</h2>
    <table>
      <tr><th>Status</th><th>Număr</th></tr>
      <tr><td>🆕 Noi</td><td><strong>${m.new_count}</strong></td></tr>
      <tr><td>📞 Contactați</td><td><strong>${m.contacted_count}</strong></td></tr>
      <tr><td>📅 Programați</td><td><strong>${m.booked_count}</strong></td></tr>
      <tr><td>✅ Finalizați</td><td><strong>${m.completed_count}</strong></td></tr>
      <tr><td>❌ Pierduți</td><td><strong>${m.lost_count}</strong></td></tr>
    </table>

    <h2>📍 Surse Lead-uri</h2>
    <table>
      <tr><th>Sursă</th><th>Număr</th></tr>
      ${Object.entries(leadsBySource).map(([source, count]) => 
        '<tr><td>' + source + '</td><td><strong>' + count + '</strong></td></tr>'
      ).join('')}
    </table>

    <div class="footer">
      <p>Raport generat automat de Lucian AutoSys</p>
      <p>📧 contact@lucian-systems.com | 📞 +40 735 105 747</p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    ...m,
    html_report: html,
    subject: '📊 Raport Săptămânal - ' + m.this_week_leads + ' lead-uri noi (Săpt. ' + m.report_week + ')'
  }
}];
